 if($route==='/capabilities/overview'){if(!hasp($perms,'capability.view')&&!hasp($perms,'capability.self'))fail(cn('\\u65e0\\u6743\\u67e5\\u770b\\u80fd\\u529b\\u753b\\u50cf'));$dept=db()->query('SELECT COALESCE(m.bm,"N/A") department,mc.dimension,ROUND(AVG(mc.score),1) avg_score FROM member_capabilities mc JOIN members m ON m.id=mc.member_id GROUP BY m.bm,mc.dimension ORDER BY department,dimension')->fetchAll();$people=db()->query('SELECT m.id,m.name,m.stuno,m.bm,m.posts,GROUP_CONCAT(CONCAT(mc.dimension,":",ROUND(mc.score,1),":",COALESCE(mc.level_label,"")) ORDER BY mc.dimension SEPARATOR "|") capability_map,ROUND(AVG(mc.score),1) avg_score FROM members m LEFT JOIN member_capabilities mc ON mc.member_id=m.id GROUP BY m.id ORDER BY avg_score DESC LIMIT 120')->fetchAll();json_out(['ok'=>true,'departments'=>$dept,'people'=>$people]);} if($route==='/approvals'){if($_SERVER['REQUEST_METHOD']==='GET')json_out(['ok'=>true,'data'=>db()->query('SELECT * FROM approvals ORDER BY id DESC LIMIT 200')->fetchAll()]);if($_SERVER['REQUEST_METHOD']==='POST'){db()->prepare('INSERT INTO approvals(type,title,applicant_stuno,payload,status,created_at) VALUES(?,?,?,?,?,?)')->execute([$input['type']??'generic',$input['title'],$user['username'],json_encode($input['payload']??[],JSON_UNESCAPED_UNICODE),'pending',now()]);audit($user['username'],'approval.create','approval',db()->lastInsertId(),$input['title']);json_out(['ok'=>true]);}}
